import React, { useState, useContext, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const EXERCISE_LIBRARY = {
  '胸部': ['杠铃卧推', '上斜哑铃推举', '哑铃飞鸟', '俯卧撑', '绳索夹胸', '下斜哑铃推举'],
  '背部': ['引体向上', '高位下拉', '杠铃划船', '硬拉', '坐姿划船', 'T型划船'],
  '腿部': ['深蹲', '腿举', '罗马尼亚硬拉', '腿屈伸', '提踵', '保加利亚分腿蹲', '哈克深蹲'],
  '肩部': ['杠铃推举', '哑铃侧平举', '哑铃前平举', '绳索面拉', '阿诺德推举'],
  '手臂': ['杠铃弯举', '哑铃弯举', '三头下压', '仰卧臂屈伸', '锤式弯举', '绳索弯举'],
  '核心': ['卷腹', '平板支撑', '悬垂举腿', '俄罗斯挺身', '侧平板', '山地爬行'],
  '有氧': ['跑步', '椭圆机', '动感单车', '划船机', '跳绳', '游泳', '爬楼梯'],
};

const CARDIO_CAT = '有氧';

const isCardioEx = (ex, cat) => {
  if (cat === CARDIO_CAT) return true;
  if (cat === 'Custom') return ['跑', '骑', '椭圆', '划船', '跳绳', '有氧', '游泳'].some(k => ex.includes(k));
  return false;
};

// ── Stepper ──────────────────────────────────────────────────────────────────
const Stepper = ({ value, onChange, min = 0, step = 1, label, isWeightField }) => {
  const val = parseFloat(value) || 0;
  const isBodyweight = isWeightField && val === 0;
  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1 }}>
      <span style={{ fontSize: 11, color: 'var(--apple-text-secondary)', marginBottom: 4, textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.04em' }}>
        {isBodyweight ? '自重' : label}
      </span>
      <div className="stepper-input">
        <div className="stepper-btn" onClick={() => onChange(Math.max(min, val - step))}>−</div>
        <input
          type={isBodyweight ? 'text' : 'number'}
          value={isBodyweight ? '自重' : value}
          onChange={e => onChange(e.target.value === '自重' ? 0 : e.target.value)}
          style={{ color: isBodyweight ? 'var(--apple-blue)' : 'inherit', fontSize: isBodyweight ? 15 : 18 }}
        />
        <div className="stepper-btn" onClick={() => onChange(val + step)}>+</div>
      </div>
    </div>
  );
};

// ── 保存模板弹窗 ──────────────────────────────────────────────────────────────
const SaveTemplateModal = ({ exercises, onSave, onClose }) => {
  const [name, setName] = useState('');
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-card" onClick={e => e.stopPropagation()}>
        <h3>保存为训练模板</h3>
        <p style={{ color: 'var(--apple-text-secondary)', fontSize: 14, marginTop: -8, marginBottom: 16 }}>
          下次训练可一键加载这套动作
        </p>
        <label>模板名称</label>
        <input type="text" placeholder="例如：胸背日、腿日" value={name}
          onChange={e => setName(e.target.value)} autoFocus />
        <div style={{ fontSize: 13, color: 'var(--apple-text-secondary)', marginBottom: 16 }}>
          包含 {exercises.length} 个动作：{exercises.map(e => e.exercise).join('、')}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button onClick={() => name.trim() && onSave(name.trim())} style={{ flex: 1 }}>保存</button>
          <button className="secondary" onClick={onClose} style={{ flex: 1 }}>取消</button>
        </div>
      </div>
    </div>
  );
};

// ── 主组件 ────────────────────────────────────────────────────────────────────
const AddWorkout = () => {
  const { token } = useContext(AuthContext);
  const navigate = useNavigate();
  const location = useLocation();
  const templateData = location.state?.template;

  const [step, setStep] = useState(templateData ? 2 : 1);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  // 当前动作
  const [exercise, setExercise] = useState(templateData?.exercises?.[0]?.exercise || '');
  const [exerciseType, setExerciseType] = useState(templateData?.exercises?.[0]?.type || 'strength');
  const [sets, setSets] = useState(templateData?.exercises?.[0]?.sets?.length
    ? templateData.exercises[0].sets.map(s => ({ weight: s.weight, reps: s.reps }))
    : [{ weight: '', reps: '' }]);
  const [notes, setNotes] = useState('');
  const [customExercise, setCustomExercise] = useState('');
  const [activeCategory, setActiveCategory] = useState('胸部');

  // 模板模式：多动作队列
  const [templateQueue, setTemplateQueue] = useState(
    templateData ? templateData.exercises.slice(1) : []
  );
  const [completedExercises, setCompletedExercises] = useState([]);

  // 上次同动作数据（实时对比）
  const [lastRecord, setLastRecord] = useState(null);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);

  // 计时器
  const [timerDuration, setTimerDuration] = useState(0);
  const [timerActive, setTimerActive] = useState(false);

  // 保存模板弹窗
  const [showSaveTemplate, setShowSaveTemplate] = useState(false);

  useEffect(() => {
    let id = null;
    if (timerActive && timerDuration > 0) {
      id = setInterval(() => setTimerDuration(p => p - 1), 1000);
    } else if (timerDuration <= 0 && timerActive) {
      setTimerActive(false);
      window.navigator?.vibrate?.(500);
    }
    return () => clearInterval(id);
  }, [timerActive, timerDuration]);

  const formatTime = s => `${Math.floor(s / 60).toString().padStart(2, '0')}:${(s % 60).toString().padStart(2, '0')}`;

  // 拉取上次数据
  const fetchLastRecord = async (ex) => {
    try {
      const res = await fetch(`${API_URL}/api/workouts/last/${encodeURIComponent(ex)}`, {
        headers: { 'x-auth-token': token },
      });
      if (res.ok) setLastRecord(await res.json());
      else setLastRecord(null);
    } catch { setLastRecord(null); }
  };

  const handleExerciseSelect = async (ex, cat) => {
    setExercise(ex);
    const cardio = isCardioEx(ex, cat);
    setExerciseType(cardio ? 'cardio' : 'strength');
    setLastRecord(null);
    setIsLoadingHistory(true);

    if (cardio) {
      setSets([{ weight: 30, reps: 300 }]);
    } else {
      await fetchLastRecord(ex);
      try {
        const res = await fetch(`${API_URL}/api/workouts/last/${encodeURIComponent(ex)}`, {
          headers: { 'x-auth-token': token },
        });
        if (res.ok) {
          const last = await res.json();
          if (last?.sets?.length) setSets(last.sets.map(s => ({ weight: s.weight, reps: s.reps })));
          else setSets([{ weight: 0, reps: 0 }]);
        }
      } catch { setSets([{ weight: 0, reps: 0 }]); }
    }

    setIsLoadingHistory(false);
    setStep(2);
  };

  const handleSetChange = (i, field, val) => {
    const ns = [...sets];
    ns[i][field] = val;
    setSets(ns);
  };

  const addSet = () => {
    const last = sets[sets.length - 1];
    setSets([...sets, { weight: last.weight, reps: last.reps }]);
  };

  const removeSet = (i) => { if (sets.length > 1) setSets(sets.filter((_, j) => j !== i)); };

  // 保存当前动作，检查是否还有模板队列里的下一个动作
  const handleSaveCurrentAndNext = async () => {
    const validSets = sets.map(s => ({
      weight: parseFloat(s.weight) || 0,
      reps: parseInt(s.reps) || 0,
    })).filter(s => exerciseType === 'cardio' ? s.weight > 0 : s.reps > 0);

    if (!validSets.length) { alert('请至少添加一组有效数据'); return; }

    // 记录到 completed 列表（批量提交）
    const record = { date, exercise, type: exerciseType, sets: validSets, notes };
    const newCompleted = [...completedExercises, record];
    setCompletedExercises(newCompleted);

    if (templateQueue.length > 0) {
      // 切换到下一个动作
      const next = templateQueue[0];
      const remaining = templateQueue.slice(1);
      setTemplateQueue(remaining);
      setExercise(next.exercise);
      setExerciseType(next.type || 'strength');
      setNotes('');
      setIsLoadingHistory(true);

      // 预填上次数据
      try {
        const res = await fetch(`${API_URL}/api/workouts/last/${encodeURIComponent(next.exercise)}`, {
          headers: { 'x-auth-token': token },
        });
        if (res.ok) {
          const last = await res.json();
          if (last?.sets?.length) setSets(last.sets.map(s => ({ weight: s.weight, reps: s.reps })));
          else setSets(next.sets?.length ? next.sets.map(s => ({ weight: s.weight, reps: s.reps })) : [{ weight: 0, reps: 0 }]);
          setLastRecord(last);
        } else {
          setSets(next.sets?.length ? next.sets.map(s => ({ weight: s.weight, reps: s.reps })) : [{ weight: 0, reps: 0 }]);
        }
      } catch {
        setSets([{ weight: 0, reps: 0 }]);
      }
      setIsLoadingHistory(false);
    } else {
      // 全部完成，批量提交
      await submitAll(newCompleted);
    }
  };

  // 单个动作直接提交
  const handleSubmit = async (e) => {
    e.preventDefault();
    const validSets = sets.map(s => ({
      weight: parseFloat(s.weight) || 0,
      reps: parseInt(s.reps) || 0,
    })).filter(s => exerciseType === 'cardio' ? s.weight > 0 : s.reps > 0);

    if (!validSets.length) { alert('请至少添加一组有效数据'); return; }

    const allRecords = [...completedExercises, { date, exercise, type: exerciseType, sets: validSets, notes }];
    await submitAll(allRecords);
  };

  const submitAll = async (records) => {
    try {
      await Promise.all(records.map(r =>
        fetch(`${API_URL}/api/workouts`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'x-auth-token': token },
          body: JSON.stringify(r),
        })
      ));
      navigate('/');
    } catch { alert('提交失败，请重试'); }
  };

  // 保存为模板
  const handleSaveTemplate = async (templateName) => {
    const allExercises = [
      ...completedExercises.map(r => ({ exercise: r.exercise, type: r.type, sets: r.sets })),
      { exercise, type: exerciseType, sets: sets.map(s => ({ weight: parseFloat(s.weight) || 0, reps: parseInt(s.reps) || 0 })) },
      ...templateQueue.map(q => ({ exercise: q.exercise, type: q.type || 'strength', sets: q.sets || [{ weight: 0, reps: 0 }] })),
    ];
    try {
      await fetch(`${API_URL}/api/workouts/templates`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-auth-token': token },
        body: JSON.stringify({ name: templateName, exercises: allExercises }),
      });
      setShowSaveTemplate(false);
      alert(`模板「${templateName}」已保存`);
    } catch { alert('保存失败，请重试'); }
  };

  // ── 对比条 ──────────────────────────────────────────────────────────────────
  const CompareBar = () => {
    if (!lastRecord || exerciseType === 'cardio') return null;
    const lastMaxW = Math.max(...lastRecord.sets.map(s => s.weight));
    const lastTotalR = lastRecord.sets.reduce((a, s) => a + s.reps, 0);
    const curMaxW = Math.max(...sets.map(s => parseFloat(s.weight) || 0));
    const curTotalR = sets.reduce((a, s) => a + (parseInt(s.reps) || 0), 0);
    const wDiff = curMaxW - lastMaxW;
    const rDiff = curTotalR - lastTotalR;
    return (
      <div className="compare-bar">
        <span className="compare-label">上次</span>
        <span className="compare-item">
          {lastMaxW === 0 ? '自重' : `${lastMaxW}kg`} · {lastTotalR}次
        </span>
        {(wDiff !== 0 || rDiff !== 0) && (
          <span className={`compare-diff ${wDiff > 0 || rDiff > 0 ? 'up' : 'down'}`}>
            {wDiff > 0 ? `+${wDiff}kg` : wDiff < 0 ? `${wDiff}kg` : ''}
            {rDiff !== 0 ? ` ${rDiff > 0 ? '+' : ''}${rDiff}次` : ''}
          </span>
        )}
      </div>
    );
  };

  // ── 步骤1：选择动作 ──────────────────────────────────────────────────────────
  if (step === 1) {
    return (
      <div className="add-workout-page">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <h2 style={{ margin: 0 }}>选择动作</h2>
          <button className="secondary" onClick={() => navigate('/')} style={{ padding: '8px 16px', fontSize: 14 }}>取消</button>
        </div>

        <div className="category-pills">
          {Object.keys(EXERCISE_LIBRARY).map(cat => (
            <div key={cat} className={`category-pill ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => setActiveCategory(cat)}>
              {cat}
            </div>
          ))}
          <div className={`category-pill ${activeCategory === 'Custom' ? 'active' : ''}`}
            style={{ border: '1px dashed var(--apple-blue)', color: activeCategory === 'Custom' ? 'white' : 'var(--apple-blue)' }}
            onClick={() => setActiveCategory('Custom')}>
            + 自定义
          </div>
        </div>

        {activeCategory !== 'Custom' ? (
          <div className="exercise-list">
            {EXERCISE_LIBRARY[activeCategory].map(ex => (
              <div key={ex} className="exercise-option" onClick={() => handleExerciseSelect(ex, activeCategory)}>
                <span>{activeCategory === CARDIO_CAT ? '🏃 ' : '🏋️ '}{ex}</span>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'left', marginTop: 20 }}>
            <label>动作名称</label>
            <input type="text" placeholder="例如：保加利亚分腿蹲" value={customExercise}
              onChange={e => setCustomExercise(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && customExercise.trim() && handleExerciseSelect(customExercise.trim(), 'Custom')}
            />
            <div style={{ display: 'flex', gap: 10 }}>
              <button style={{ flex: 1 }} disabled={!customExercise.trim()}
                onClick={() => handleExerciseSelect(customExercise.trim(), 'Custom')}>
                力量训练
              </button>
              <button className="secondary" disabled={!customExercise.trim()}
                style={{ flex: 1, background: 'rgba(255,149,0,0.1)', color: '#d87000', border: '1px solid rgba(255,149,0,0.3)' }}
                onClick={() => { setExerciseType('cardio'); handleExerciseSelect(customExercise.trim(), 'Custom'); }}>
                有氧训练
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // ── 步骤2：记录组数 ──────────────────────────────────────────────────────────
  const isCardio = exerciseType === 'cardio';
  const isTemplateMode = templateData !== undefined;
  const totalInTemplate = templateData ? templateData.exercises.length : 0;
  const currentIndex = completedExercises.length;

  return (
    <div className="add-workout-page">
      {/* 模板进度条 */}
      {isTemplateMode && (
        <div className="template-progress">
          <div className="template-progress-bar">
            {templateData.exercises.map((_, i) => (
              <div key={i} className={`tp-dot ${i < currentIndex ? 'done' : i === currentIndex ? 'current' : 'upcoming'}`} />
            ))}
          </div>
          <div className="template-progress-label">
            {templateData.name} · 第 {currentIndex + 1} / {totalInTemplate} 个动作
          </div>
        </div>
      )}

      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 16 }}>
        {!isTemplateMode && (
          <button className="secondary" onClick={() => setStep(1)}
            style={{ padding: '8px 14px', marginRight: 14, borderRadius: 12 }}>
            ←
          </button>
        )}
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <h2 style={{ margin: 0 }}>{exercise}</h2>
            <span className={`type-tag ${isCardio ? 'cardio' : 'strength'}`}>
              {isCardio ? '有氧' : '力量'}
            </span>
          </div>
          {isLoadingHistory && (
            <div style={{ fontSize: 12, color: 'var(--apple-text-secondary)', marginTop: 2 }}>读取历史记录中...</div>
          )}
        </div>
        {/* 保存为模板按钮（非模板模式才显示） */}
        {!isTemplateMode && (
          <button className="secondary" style={{ marginLeft: 'auto', fontSize: 13, padding: '6px 12px' }}
            onClick={() => setShowSaveTemplate(true)}>
            保存模板
          </button>
        )}
      </div>

      {/* 实时对比条 */}
      <CompareBar />

      <form onSubmit={handleSubmit} style={{ textAlign: 'left' }}>
        <label>日期</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} required style={{ marginBottom: 20 }} />

        <label style={{ marginBottom: 8, display: 'block' }}>{isCardio ? '时长与消耗' : '组数与次数'}</label>

        {sets.map((set, i) => (
          <div key={i} className="set-row">
            {!isCardio && <div className="set-number">{i + 1}</div>}
            <Stepper label={isCardio ? '时长 (分钟)' : '重量 (kg)'}
              value={set.weight} step={isCardio ? 5 : 2.5} isWeightField={!isCardio}
              onChange={v => handleSetChange(i, 'weight', v)} />
            <Stepper label={isCardio ? '消耗 (千卡)' : '次数'}
              value={set.reps} step={isCardio ? 10 : 1}
              onChange={v => handleSetChange(i, 'reps', v)} />
            {sets.length > 1 && (
              <button type="button" className="secondary"
                style={{ width: 38, height: 38, padding: 0, borderRadius: 10, fontSize: 18, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                onClick={() => removeSet(i)}>×</button>
            )}
          </div>
        ))}

        {!isCardio && (
          <button type="button" className="secondary add-set-btn" onClick={addSet}>
            + 添加一组
          </button>
        )}

        {/* 休息计时 */}
        {!isCardio && (
          <div className="timer-section">
            <span className="timer-section-label">休息计时</span>
            <div className="quick-timer-btns">
              {[60, 90, 120, 180].map(s => (
                <button key={s} type="button" onClick={() => { setTimerDuration(s); setTimerActive(true); }}>
                  {Math.floor(s / 60)}:{String(s % 60).padStart(2, '0')}
                </button>
              ))}
            </div>
          </div>
        )}

        <label>备注（选填）</label>
        <textarea placeholder="今天的状态、心得..." value={notes}
          onChange={e => setNotes(e.target.value)} rows={2} style={{ marginBottom: 20 }} />

        <div style={{ display: 'flex', gap: 10 }}>
          {/* 模板模式：下一个动作 or 完成训练 */}
          {isTemplateMode ? (
            <>
              {templateQueue.length > 0 ? (
                <button type="button" style={{ flex: 1, fontSize: 16, padding: 14 }} onClick={handleSaveCurrentAndNext}>
                  下一个：{templateQueue[0].exercise} →
                </button>
              ) : (
                <button type="button" style={{ flex: 1, fontSize: 16, padding: 14, background: '#34c759' }}
                  onClick={handleSaveCurrentAndNext}>
                  完成全部训练
                </button>
              )}
            </>
          ) : (
            <button type="submit" style={{ flex: 1, fontSize: 16, padding: 14 }}>保存训练</button>
          )}
        </div>
      </form>

      {/* 休息计时器浮条 */}
      {timerActive && (
        <div className="rest-timer-bar">
          <div className="timer-clock">⏱ {formatTime(timerDuration)}</div>
          <div className="timer-controls">
            <button type="button" onClick={() => setTimerDuration(p => p + 30)}>+30s</button>
            <button type="button" onClick={() => setTimerActive(false)}>结束</button>
          </div>
        </div>
      )}

      {/* 保存模板弹窗 */}
      {showSaveTemplate && (
        <SaveTemplateModal
          exercises={[
            ...completedExercises,
            { exercise, type: exerciseType },
            ...templateQueue,
          ]}
          onSave={handleSaveTemplate}
          onClose={() => setShowSaveTemplate(false)}
        />
      )}
    </div>
  );
};

export default AddWorkout;
